from itertools import permutations

distributions = set()
for a in range(31):
    for b in range(31):
        c = 30 - a - b
        if c < 0: continue
        if (b==a+6)or(a==b+6)or(c==a+6)or(a==c+6)or(c==b+6)or(b==c+6):
            if max(a,b,c)>=2:
                distributions.add(tuple(sorted([a,b,c])))

def min_bob_wins(strategy, dist):
    best_for_host = float('inf')
    for perm in permutations(dist):
        wins = sum(strategy[i] for i in range(3) if strategy[i] <= perm[i])
        best_for_host = min(best_for_host, wins)
    return best_for_host

def guaranteed_wins(strategy):
    return min(min_bob_wins(strategy, dist) for dist in distributions)

# Search broader strategy space
best = 0
best_strategy = None
for g1 in range(0, 31):
    for g2 in range(g1, 31):
        for g3 in range(g2, 31):
            w = guaranteed_wins((g1, g2, g3))
            if w > best:
                best = w
                best_strategy = (g1, g2, g3)

print(f"Best guaranteed winnings: {best} coins = ${best * 1000:,}")
print(f"Optimal strategy: {best_strategy}")

# Show which distributions are binding (give the minimum)
print("\nBinding distributions for optimal strategy:")
for dist in sorted(distributions):
    w = min_bob_wins(best_strategy, dist)
    if w == best:
        print(f"  {dist}: wins {w}")
